VALUES
  ('generalpolice-94737317-moex-00362', 'generalpolice-94737317', 'generalpolice-94737317-moex-112-b182839b', 'sub-generalpolice-94737317-05', NULL, 'single_choice', 'A直轄市自治條例規定，以藝文表演為職業之街頭藝人，須經該市主管機關核發表演許可證，始得在該市 之公共空間從事藝文表演。有關上開規定，下列敘述何者正確？', '["此規定僅限制街頭藝人從事工作之地點，尚不構成對職業自由之限制", "此規定構成對職業自由之限制，但職業自由之限制僅能以法律定之，故違反法律保留原則", "此規定不構成對表現自由之限制", "此規定構成對職業自由之限制，其得授權地方行政機關對此限制事宜訂定自治規則為具體規範"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:47+00:00", "source_pdf_sha1": "40162905cbc1", "answer_pdf_sha1": "b681be7ebd22", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "402", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(中華民國憲法概要、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00363', 'generalpolice-94737317', 'generalpolice-94737317-moex-112-b182839b', 'sub-generalpolice-94737317-05', NULL, 'single_choice', '訴訟權旨在確保人民之權利受侵害時，享有依法向法院提起適時審判的請求權，包含聽審、公正程序、公 開審判請求權及下列何者？', '["社會福利請求權", "經濟資源分配權", "程序上之平等權", "人性尊嚴保障權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:47+00:00", "source_pdf_sha1": "40162905cbc1", "answer_pdf_sha1": "b681be7ebd22", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "402", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(中華民國憲法概要、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00364', 'generalpolice-94737317', 'generalpolice-94737317-moex-112-b182839b', 'sub-generalpolice-94737317-05', NULL, 'single_choice', '憲法上有關國民受教育之規定，下列敘述何者錯誤？', '["人民受國民教育既係權利也是義務", "人民受基本教育，免納學費", "6歲至15歲之學齡兒童，一律受基本教育", "國家對於全國公私立教育文化機關，有監督之權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:47+00:00", "source_pdf_sha1": "40162905cbc1", "answer_pdf_sha1": "b681be7ebd22", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "402", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(中華民國憲法概要、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
