  ('generalpolice-94737317-moex-00370', 'generalpolice-94737317', 'generalpolice-94737317-moex-112-b182839b', 'sub-generalpolice-94737317-05', NULL, 'single_choice', '關於行政院院長，下列敘述何者正確？', '["行政院副院長、各部會首長及不管部政務委員之任命，於經總統同意後，由行政院院長為之", "行政院院長應向立法院提出施政方針及施政報告", "行政院院長對於應由立法院議決之議案，有應立法院各委員會之邀請列席接受質詢或備詢之義務", "立法院對行政院院長所提出之不信任案如未獲通過，於同一會期內不得對同一行政院院長再提不信任 案"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:47+00:00", "source_pdf_sha1": "40162905cbc1", "answer_pdf_sha1": "b681be7ebd22", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "402", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(中華民國憲法概要、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00371', 'generalpolice-94737317', 'generalpolice-94737317-moex-112-b182839b', 'sub-generalpolice-94737317-05', NULL, 'single_choice', '依憲法增修條文及司法院大法官解釋意旨，關於立法委員選舉，下列敘述何者錯誤？', '["採單一選區制與比例代表制混合之兩票制，分別以區域候選人及政黨為投票對象", "山地原住民立法委員之選舉，依直轄市、縣市、鄉鎮市之原住民人口比例劃分選舉區", "獲得政黨選舉票百分之五以上之政黨始得分配全國不分區及僑居國外國民立法委員之席次", "單一選區之區域選舉結果與政黨選舉票之選舉結果分開計算兩類立法委員當選人名額"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:47+00:00", "source_pdf_sha1": "40162905cbc1", "answer_pdf_sha1": "b681be7ebd22", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "402", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(中華民國憲法概要、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL)
